    if (!href || href.startsWith('javascript:') || href.startsWith('mailto:')) return;

    // Check if link matches any platform
    for (const [domain, info] of Object.entries(platforms)) {
      if (href.includes(domain)) {
        if (seenUrls.has(href)) return;
        seenUrls.add(href);

        links.push({
          url: link.href,
          platform: info.name,
          icon: info.icon,
          text: text || info.name,
          type: 'platform'
        });
