  const containerSelector = SELECTORS?.container?.primary || '[role="main"]';
  const bodySelectors = SELECTORS?.body || [
    '.a3s.aiL', '.a3s', '.ii.gt', '[data-message-id]',
    '.gmail_quote', 'div[dir="ltr"]', '.Am.aiL', '.Am'
