// @ts-nocheck
// Shared Extractors for Bid Extractor
// Common extraction functions used by Gmail and Outlook content scripts
// Loaded via manifest.json before gmail.js / outlook.js

(function() {
  'use strict';

  // Prevent double-initialization
  if (window.SharedExtractors) return;

  /**
   * Check if text looks like a greeting rather than a project name
   * @param {string} text
   * @returns {boolean}
   */
  function isGreeting(text) {
    const cleaned = text.replace(/^[:\-\s]+|[:\-\s,]+$/g, '').trim();
    return /^(Hello|Hi|Hey|Dear|Good\s+(morning|afternoon|evening))\b/i.test(cleaned);
  }

  /**
   * Extract project name from subject/body
   * @param {string} subject - Email subject line
   * @param {string} body - Email body text
   * @returns {string}
   */
  function extractProjectName(subject, body) {
    const patterns = [
      /(?:RFQ|RFP|ITB|Bid|Quote|Proposal)[:\s-]*(.+?)(?:\s*-|\s*\||$)/i,
      /Project[:\s]+(.+?)(?:\s*-|\s*\||$)/i,
      /(?:RE:|FW:)?\s*(.+?)(?:\s*-\s*(?:RFQ|Bid|Steel))/i,
    ];

    for (const pattern of patterns) {
      const match = subject.match(pattern);
      if (match?.[1]) {
        const result = cleanText(match[1]);
        if (!isGreeting(result)) return result;
      }
    }

    // Fallback: use subject without common prefixes, but reject greetings
    const fallback = cleanText(subject.replace(/^(RE:|FW:|RFQ|RFP|ITB)[:\s]*/gi, ''));
    if (!isGreeting(fallback) && fallback.length > 3) {
      return fallback;
    }

    // Subject was a greeting — try body for explicit project/job name fields
    const bodyPatterns = [
      /Project(?:\s+Name)?[:\s]+(.+?)(?:\n|$)/i,
      /Job(?:\s+Name)?[:\s]+(.+?)(?:\n|$)/i,
    ];

    for (const pattern of bodyPatterns) {
      const match = body.match(pattern);
      if (match?.[1]) {
        const result = cleanText(match[1]);
        if (!isGreeting(result) && result.length > 3) return result;
      }
    }

    return 'Untitled Project';
  }

  /**
   * Extract General Contractor name
   * @param {string} senderName - Email sender name
   * @param {string} body - Email body text
   * @returns {string}
   */
  function extractGCName(senderName, body) {
    const patterns = [
      /(?:General\s+Contractor|GC|Prime)[:\s]+(.+?)(?:\n|$)/i,
      /(?:From|Sent\s+by)[:\s]+(.+?)(?:\n|$)/i,
      /(.+?)\s+(?:Construction|Builders|Contracting|General)/i,
    ];

    for (const pattern of patterns) {
      const match = body.match(pattern);
      if (match?.[1]) {
        const gc = cleanText(match[1]);
        if (gc.length > 3 && gc.length < 100) {
          return gc;
        }
      }
    }

    if (senderName) {
      const companyMatch = senderName.match(/(?:at|@|from)\s+(.+)/i);
      if (companyMatch) {
        return cleanText(companyMatch[1]);
      }

      if (senderName.match(/(?:Construction|Builders|Contracting|Inc|LLC|Corp)/i)) {
        return cleanText(senderName);
      }
    }

    return senderName || 'Unknown';
  }

  /**
   * Extract bid date from email body
   * @param {string} body - Email body text
   * @returns {string}
   */
  function extractBidDate(body) {
    const patterns = [
      /(?:Bid|Due|Deadline|Submit(?:tal)?)\s*(?:Date|By)?[:\s]+(\w+\s+\d{1,2},?\s+\d{4})/i,
      /(?:Bid|Due|Deadline|Submit(?:tal)?)\s*(?:Date|By)?[:\s]+(\d{1,2}\/\d{1,2}\/\d{2,4})/i,
      /(?:Bid|Due|Deadline)s?\s+(?:due\s+)?(\w+\s+\d{1,2}(?:,?\s+\d{4})?)/i,
      /by\s+\d{1,2}:\d{2}\s*(?:AM|PM)?\s+on\s+(\w+\s+\d{1,2},?\s+\d{4})/i,
      /(?:Bid|Due|Deadline)[:\s]+(\d{1,2}-\d{1,2}-\d{2,4})/i,
    ];

    for (const pattern of patterns) {
      const match = body.match(pattern);
      if (match?.[1]) {
        return formatDate(match[1]);
      }
    }

    // Try to find any date-like pattern near "bid" or "due"
    const contextMatch = body.match(/(?:bid|due|deadline).{0,50}(\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4})/i);
    if (contextMatch) {
      return formatDate(contextMatch[1]);
    }

    return '';
  }

  /**
   * Extract location from email body
   * @param {string} body - Email body text
   * @returns {string}
   */
  function extractLocation(body) {
    const patterns = [
      /(?:Location|Site|Address|City)[:\s]+(.+?)(?:\n|$)/i,
      /(?:Project\s+)?(?:Location|Site)[:\s]+(.+?)(?:\n|$)/i,
      /in\s+([A-Z][a-z]+(?:,?\s+[A-Z]{2})?)\s+(?:area|region|metro)/i,
    ];

    for (const pattern of patterns) {
      const match = body.match(pattern);
      if (match?.[1]) {
        const location = cleanText(match[1]);
        if (location.length > 3 && location.length < 100) {
          return location;
        }
      }
    }

    // Try to find city, state pattern
    const cityStateMatch = body.match(/([A-Z][a-z]+(?:\s+[A-Z][a-z]+)?),\s*([A-Z]{2})\s+\d{5}/);
    if (cityStateMatch) {
      return `${cityStateMatch[1]}, ${cityStateMatch[2]}`;
    }

    return '';
  }

  /**
   * Extract scope of work from email body
   * @param {string} body - Email body text
   * @returns {string}
   */
  function extractScope(body) {
    const patterns = [
      /(?:Scope|Work|Package)[:\s]+(.+?)(?:\n\n|\n[A-Z]|$)/is,
      /(?:Steel|Structural)\s+(?:Package|Scope)[:\s]+(.+?)(?:\n|$)/i,
      /(?:includes?|requiring)[:\s]+(.+?)(?:\n\n|$)/is,
    ];

    for (const pattern of patterns) {
      const match = body.match(pattern);
      if (match?.[1]) {
        const scope = cleanText(match[1]);
        if (scope.length > 10 && scope.length < 500) {
          return scope.substring(0, 200);
        }
      }
    }

    // Look for steel-specific keywords
    const steelKeywords = ['structural steel', 'misc steel', 'miscellaneous metals',
                           'steel fabrication', 'erection', 'joist', 'deck'];
    for (const keyword of steelKeywords) {
      if (body.toLowerCase().includes(keyword)) {
        return 'Structural Steel / Misc Metals';
      }
    }

    return '';
  }

  /**
   * Extract phone number from email body
   * @param {string} body - Email body text
   * @returns {string}
   */
  function extractPhone(body) {
    const phoneMatch = body.match(/(?:Phone|Tel|Cell|Mobile|Direct)?[:\s]*(\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4})/i);
    return phoneMatch?.[1] || '';
  }

  /**
   * Extract email from text
   * @param {string} text
   * @returns {string}
   */
  function extractEmailFromText(text) {
    const match = text.match(/([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9_-]+)/);
    return match?.[1] || '';
  }

  /**
   * Get file type from filename
   * @param {string} filename
   * @returns {string}
   */
  function getFileType(filename) {
    const ext = filename.split('.').pop()?.toLowerCase();
    const types = {
      pdf: 'document',
      dwg: 'drawing',
      dxf: 'drawing',
      xlsx: 'spreadsheet',
      xls: 'spreadsheet',
      doc: 'document',
      docx: 'document',
      zip: 'archive'
    };
    return types[ext] || 'file';
  }

  /**
   * Extract download links from bid portals and file sharing services
   * @param {Element} emailBody - DOM element containing email body
   * @param {Object|null} platformsConfig - Platforms config from ConfigLoader
   * @returns {Array} Array of download link objects
   */
  function extractDownloadLinks(emailBody, platformsConfig) {
    const links = [];
    const allLinks = emailBody.querySelectorAll('a[href]');

    // Use platforms from config or fallback to defaults
    const platforms = platformsConfig || {
      'buildingconnected.com': { name: 'BuildingConnected', icon: '🏗️' },
      'planhub.com': { name: 'PlanHub', icon: '📐' },
      'isqft.com': { name: 'iSqFt', icon: '📊' },
      'procore.com': { name: 'Procore', icon: '🔷' },
      'smartbidnet.com': { name: 'SmartBid', icon: '💡' },
      'construction.com': { name: 'Dodge/Construction', icon: '🔶' },
      'constructconnect.com': { name: 'ConstructConnect', icon: '🔗' },
      'plangrid.com': { name: 'PlanGrid', icon: '📱' },
      'bluebeam.com': { name: 'Bluebeam', icon: '🔵' },
      'pipelinesuite.com': { name: 'Pipeline Suite', icon: '🔧' },
      'e-builder.net': { name: 'e-Builder', icon: '🏢' },
      'dropbox.com': { name: 'Dropbox', icon: '📦' },
      'box.com': { name: 'Box', icon: '📁' },
      'drive.google.com': { name: 'Google Drive', icon: '🔷' },
      'docs.google.com': { name: 'Google Docs', icon: '📄' },
      'onedrive.live.com': { name: 'OneDrive', icon: '☁️' },
      'sharepoint.com': { name: 'SharePoint', icon: '📂' },
      '1drv.ms': { name: 'OneDrive', icon: '☁️' },
      'sharefile.com': { name: 'ShareFile', icon: '📤' },
      'wetransfer.com': { name: 'WeTransfer', icon: '📨' },
      'we.tl': { name: 'WeTransfer', icon: '📨' },
      'hightail.com': { name: 'Hightail', icon: '✈️' },
      'egnyte.com': { name: 'Egnyte', icon: '📊' },
      'planswift.com': { name: 'PlanSwift', icon: '📏' },
      'onscreentakeoff.com': { name: 'On-Screen Takeoff', icon: '📐' },
      'bluebeamcloud.com': { name: 'Bluebeam Cloud', icon: '🔵' },
      'amazonaws.com': { name: 'AWS Download', icon: '☁️' },
      'blob.core.windows.net': { name: 'Azure Storage', icon: '☁️' },
    };

    const seenUrls = new Set();

    allLinks.forEach(link => {
      const href = link.href?.toLowerCase() || '';
      const text = link.innerText?.trim() || '';

      if (!href || href.startsWith('javascript:') || href.startsWith('mailto:')) return;

      // Check if link matches any platform
      for (const [domain, info] of Object.entries(platforms)) {
        if (href.includes(domain)) {
          if (seenUrls.has(href)) return;
          seenUrls.add(href);

          links.push({
            url: link.href,
            platform: info.name,
            icon: info.icon,
            text: text || info.name,
            type: 'platform'
          });
          return;
        }
      }

      // Check for direct file downloads
      const fileExtensions = ['.pdf', '.dwg', '.dxf', '.zip', '.rar', '.xlsx', '.xls', '.doc', '.docx'];
      for (const ext of fileExtensions) {
        if (href.includes(ext)) {
          if (seenUrls.has(href)) return;
          seenUrls.add(href);

          links.push({
            url: link.href,
            platform: 'Direct Download',
            icon: '📥',
            text: text || `Download ${ext.toUpperCase()}`,
            type: 'file',
            extension: ext
          });
          return;
        }
      }

      // Check for links with download-related text
      const downloadKeywords = ['download', 'view plans', 'view drawings', 'access documents',
                                'bid documents', 'project documents', 'click here to view',
                                'specifications', 'addendum', 'plans and specs'];
      const textLower = text.toLowerCase();

      for (const keyword of downloadKeywords) {
        if (textLower.includes(keyword)) {
          if (seenUrls.has(href)) return;
          seenUrls.add(href);

          links.push({
            url: link.href,
            platform: 'Document Link',
            icon: '📄',
            text: text,
            type: 'document'
          });
          return;
        }
      }
    });

    return links;
  }

  /**
   * Clean text by normalizing whitespace and removing leading/trailing junk
   * @param {string} text
   * @returns {string}
   */
  function cleanText(text) {
    return text
      .replace(/\s+/g, ' ')
      .replace(/^\s+|\s+$/g, '')
      .replace(/^[:\-\s]+|[:\-\s]+$/g, '');
  }

  /**
   * Format a date string to locale format
   * @param {string} dateStr
   * @returns {string}
   */
  function formatDate(dateStr) {
    try {
      const date = new Date(dateStr);
      if (isNaN(date.getTime())) {
        return dateStr;
      }
      return date.toLocaleDateString('en-US', {
        month: '2-digit',
        day: '2-digit',
        year: 'numeric'
      });
    } catch {
      return dateStr;
    }
  }

  /**
   * Debounce a function
   * @param {Function} fn - Function to debounce
   * @param {number} delay - Delay in ms
   * @returns {Function}
   */
  function debounce(fn, delay) {
    let timer = null;
    return function(...args) {
      if (timer) clearTimeout(timer);
      timer = setTimeout(() => {
        fn.apply(this, args);
        timer = null;
      }, delay);
    };
  }

  // Export to window
  window.SharedExtractors = {
    isGreeting,
    extractProjectName,
    extractGCName,
    extractBidDate,
    extractLocation,
    extractScope,
    extractPhone,
    extractEmailFromText,
    getFileType,
    extractDownloadLinks,
    cleanText,
    formatDate,
    debounce
  };

})();

// @ts-nocheck
// Popup Calendar Utilities for Bid Extractor
// Calendar event creation, Google Calendar, Outlook, ICS file generation

(function() {
  'use strict';

  if (window.PopupCalendar) return;

  /**
   * Parse bid date string into Date object
   * @param {string} dateStr
   * @returns {Date|null}
   */
  function parseBidDate(dateStr) {
    if (!dateStr) return null;

    // Try MM/DD/YYYY
    var match = dateStr.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
    if (match) {
      return new Date(match[3], match[1] - 1, match[2]);
    }

    // Try YYYY-MM-DD
    match = dateStr.match(/(\d{4})-(\d{1,2})-(\d{1,2})/);
    if (match) {
      return new Date(match[1], match[2] - 1, match[3]);
    }

    // Try Month DD, YYYY
    match = dateStr.match(/(\w+)\s+(\d{1,2}),?\s*(\d{4})/);
    if (match) {
      var months = {
        'january': 0, 'february': 1, 'march': 2, 'april': 3, 'may': 4, 'june': 5,
        'july': 6, 'august': 7, 'september': 8, 'october': 9, 'november': 10, 'december': 11,
        'jan': 0, 'feb': 1, 'mar': 2, 'apr': 3, 'jun': 5, 'jul': 6, 'aug': 7, 'sep': 8, 'oct': 9, 'nov': 10, 'dec': 11
      };
      var month = months[match[1].toLowerCase()];
      if (month !== undefined) {
        return new Date(match[3], month, match[2]);
      }
    }

    // Try DD Month YYYY
    match = dateStr.match(/(\d{1,2})\s+(\w+)\s+(\d{4})/);
    if (match) {
      var months2 = {
        'january': 0, 'february': 1, 'march': 2, 'april': 3, 'may': 4, 'june': 5,
        'july': 6, 'august': 7, 'september': 8, 'october': 9, 'november': 10, 'december': 11,
        'jan': 0, 'feb': 1, 'mar': 2, 'apr': 3, 'jun': 5, 'jul': 6, 'aug': 7, 'sep': 8, 'oct': 9, 'nov': 10, 'dec': 11
      };
      var month2 = months2[match[2].toLowerCase()];
      if (month2 !== undefined) {
        return new Date(match[3], month2, match[1]);
      }
    }

    // Fallback to Date.parse
    var parsed = Date.parse(dateStr);
    if (!isNaN(parsed)) {
      return new Date(parsed);
    }

    return null;
  }

  /**
   * Create calendar event data from bid extraction
   * @param {Object} data - Bid extraction data
   * @returns {Object} Calendar event object
   */
  function createCalendarEvent(data) {
    var bidDate = parseBidDate(data.bidDate);

    // Default to today + 7 days if no valid date
    var eventDate = bidDate || new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);

    // Extract time from bidTime field, bidDate, or default to 2 PM
    var hours = 14;
    var minutes = 0;

    var timeSource = data.bidTime || data.bidDate || '';
    if (timeSource) {
      var timeMatch = timeSource.match(/(\d{1,2}):(\d{2})\s*(am|pm)?/i);
      if (timeMatch) {
        hours = parseInt(timeMatch[1]);
        minutes = parseInt(timeMatch[2]);
        if (timeMatch[3]?.toLowerCase() === 'pm' && hours < 12) hours += 12;
        if (timeMatch[3]?.toLowerCase() === 'am' && hours === 12) hours = 0;
      }
    }

    eventDate.setHours(hours, minutes, 0, 0);

    // End time is 1 hour later
    var endDate = new Date(eventDate.getTime() + 60 * 60 * 1000);

    return {
      title: 'BID DUE: ' + (data.project || 'Unknown Project'),
      description: 'Project: ' + (data.project || 'N/A') + '\n' +
        'General Contractor: ' + (data.gcCompany || data.gc || 'N/A') + '\n' +
        'Project Manager: ' + (data.projectManager || 'N/A') + '\n' +
        'Location: ' + (data.location || 'N/A') + '\n' +
        'Scope: ' + (data.scope || 'N/A') + '\n' +
        (data.submissionInstructions ? '\nSubmission: ' + data.submissionInstructions + '\n' : '') +
        'Contact: ' + (data.projectManager || data.contact || 'N/A') + '\n' +
        'Email: ' + (data.gcEmail || data.email || 'N/A') + '\n' +
        'Phone: ' + (data.gcPhone || data.phone || 'N/A') + '\n\n' +
        'Attachments: ' + (data.attachments?.length || 0) + ' file(s)',
      location: data.location || '',
      start: eventDate,
      end: endDate
    };
  }

  /**
   * Format date for Google Calendar URL (YYYYMMDDTHHmmss)
   * @param {Date} date
   * @returns {string}
   */
  function formatDateGoogle(date) {
    return date.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
  }

  /**
   * Create Google Calendar URL
   * @param {Object} event - Calendar event object
   * @returns {string}
   */
  function createGoogleCalendarUrl(event) {
    var baseUrl = 'https://calendar.google.com/calendar/render';
    var params = new URLSearchParams({
      action: 'TEMPLATE',
      text: event.title,
      dates: formatDateGoogle(event.start) + '/' + formatDateGoogle(event.end),
      details: event.description,
      location: event.location
    });

    return baseUrl + '?' + params.toString();
  }

  /**
   * Create Outlook Calendar URL
   * @param {Object} event - Calendar event object
   * @returns {string}
   */
  function createOutlookCalendarUrl(event) {
    var baseUrl = 'https://outlook.live.com/calendar/0/deeplink/compose';
    var params = new URLSearchParams({
      subject: event.title,
      startdt: event.start.toISOString(),
      enddt: event.end.toISOString(),
      body: event.description,
      location: event.location,
      path: '/calendar/action/compose',
      rru: 'addevent'
    });

    return baseUrl + '?' + params.toString();
  }

  /**
   * Create .ics file content
   * @param {Object} event - Calendar event object
   * @returns {string}
   */
  function createICSFile(event) {
    function formatICSDate(date) {
      return date.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
    }

    function escapeICS(str) {
      return (str || '').replace(/\n/g, '\\n').replace(/,/g, '\\,').replace(/;/g, '\\;');
    }

    var uid = 'bid-' + Date.now() + '@bidextractor';
    var now = formatICSDate(new Date());

    return 'BEGIN:VCALENDAR\n' +
      'VERSION:2.0\n' +
      'PRODID:-//Bid Extractor//Chrome Extension//EN\n' +
      'BEGIN:VEVENT\n' +
      'UID:' + uid + '\n' +
      'DTSTAMP:' + now + '\n' +
      'DTSTART:' + formatICSDate(event.start) + '\n' +
      'DTEND:' + formatICSDate(event.end) + '\n' +
      'SUMMARY:' + escapeICS(event.title) + '\n' +
      'DESCRIPTION:' + escapeICS(event.description) + '\n' +
      'LOCATION:' + escapeICS(event.location) + '\n' +
      'BEGIN:VALARM\n' +
      'TRIGGER:-P1D\n' +
      'ACTION:DISPLAY\n' +
      'DESCRIPTION:Bid due tomorrow: ' + escapeICS(event.title) + '\n' +
      'END:VALARM\n' +
      'BEGIN:VALARM\n' +
      'TRIGGER:-PT2H\n' +
      'ACTION:DISPLAY\n' +
      'DESCRIPTION:Bid due in 2 hours: ' + escapeICS(event.title) + '\n' +
      'END:VALARM\n' +
      'END:VEVENT\n' +
      'END:VCALENDAR';
  }

  // Export
  window.PopupCalendar = {
    parseBidDate: parseBidDate,
    createCalendarEvent: createCalendarEvent,
    formatDateGoogle: formatDateGoogle,
    createGoogleCalendarUrl: createGoogleCalendarUrl,
    createOutlookCalendarUrl: createOutlookCalendarUrl,
    createICSFile: createICSFile
  };

})();

// @ts-nocheck
// Gmail Content Script for Bid Extractor
// Uses SharedExtractors (loaded before this script via manifest)

// Config storage (loaded on init via shared ConfigLoader)
let SELECTORS = null;
let PLATFORMS = null;

// Load configs using the shared ConfigLoader (injected before this script)
(async function initConfigs() {
  try {
    const loader = window.ConfigLoader;
    if (!loader) {
      console.warn('Bid Extractor: ConfigLoader not available, using defaults');
      return;
    }
    const [selectorsConfig, platformsConfig] = await Promise.all([
      loader.loadConfig('selectors'),
      loader.loadConfig('platforms')
    ]);
    SELECTORS = selectorsConfig.gmail;
    PLATFORMS = {
      ...platformsConfig.bidPlatforms,
      ...platformsConfig.fileSharingServices,
      ...platformsConfig.drawingServices,
      ...platformsConfig.cloudStorage
    };
    console.log('Bid Extractor: Gmail configs loaded');
  } catch (error) {
    console.warn('Bid Extractor: Failed to load configs, using defaults:', error);
  }
})();

// Shared helpers (loaded before this script)
const SE = window.SharedExtractors || {};

// Listen for messages from popup
chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  if (request.action === 'extract') {
    extractBidInfo()
      .then(data => sendResponse({ success: true, data }))
      .catch(error => sendResponse({ success: false, error: error.message }));
    return true;
  }
});

// Main extraction function
async function extractBidInfo() {
  console.log('Bid Extractor: Starting extraction...');

  const containerSelector = SELECTORS?.container?.primary || '[role="main"]';
  const bodySelectors = SELECTORS?.body || [
    '.a3s.aiL', '.a3s', '.ii.gt', '[data-message-id]',
    '.gmail_quote', 'div[dir="ltr"]', '.Am.aiL', '.Am'
  ];
  const fallbackSelectors = SELECTORS?.bodyFallback || [
    '.a3s.aiL', '.a3s', '.gs .ii.gt', '[role="listitem"] .a3s', '.nH .a3s'
  ];

  let emailBody = null;
  let emailContainer = null;

  // Strategy 1: Find container and body using SafeQuery
  emailContainer = document.querySelector(containerSelector);

  if (emailContainer && window.SafeQuery) {
    emailBody = SafeQuery.query(bodySelectors, emailContainer, {
      name: 'gmail-email-body',
      minTextLength: 10,
      silent: true
    });
  } else if (emailContainer) {
    for (const selector of bodySelectors) {
      emailBody = emailContainer.querySelector(selector);
      if (emailBody && emailBody.innerText?.trim().length > 10) break;
    }
  }

  // Strategy 2: Look for email content anywhere in the page
  if (!emailBody) {
    if (window.SafeQuery) {
      emailBody = SafeQuery.query(fallbackSelectors, document, {
        name: 'gmail-email-body-fallback',
        minTextLength: 10,
        silent: true
      });
    } else {
      for (const selector of fallbackSelectors) {
        emailBody = document.querySelector(selector);
        if (emailBody && emailBody.innerText?.trim().length > 10) break;
      }
    }
  }

  // Strategy 3: Look for any substantial text content in the main area
  if (!emailBody && emailContainer) {
    const allDivs = emailContainer.querySelectorAll('div');
    for (const div of allDivs) {
      const text = div.innerText?.trim() || '';
      if (text.length > 100 && !div.querySelector('div[innerText]')) {
        emailBody = div;
        break;
      }
    }
  }

  if (!emailBody) {
    if (window.SafeQuery) {
      SafeQuery.reportFailure('gmail-email-body-all-strategies', [...bodySelectors, ...fallbackSelectors], document);
    }
    throw new Error('Could not find email content - try refreshing the page');
  }

  const emailText = emailBody.innerText || '';

  // Read ALL messages in the thread
  const allMessageBodies = document.querySelectorAll('.a3s.aiL, .a3s');
  const threadTexts = [];
  allMessageBodies.forEach(msgBody => {
    const msgText = msgBody.innerText?.trim();
    if (msgText && msgText.length > 10) {
      threadTexts.push(msgText);
    }
  });

  // Get email subject
  const subjectSelectors = SELECTORS?.subject || ['h2[data-thread-perm-id]', '[data-thread-perm-id] span', '.hP'];
  let subjectEl = null;
  for (const sel of subjectSelectors) {
    subjectEl = document.querySelector(sel);
    if (subjectEl) break;
  }
  const subject = subjectEl?.innerText || '';

  // Get sender info
  const senderSelectors = SELECTORS?.sender || ['.gD', '[email]'];
  let senderEl = null;
  for (const sel of senderSelectors) {
    senderEl = document.querySelector(sel);
    if (senderEl) break;
  }
  const senderEmail = senderEl?.getAttribute('email') || '';
  const senderName = senderEl?.getAttribute('name') || senderEl?.innerText || '';

  // Use EmailParser for deep extraction
  const parsed = (typeof EmailParser !== 'undefined')
    ? EmailParser.parseFullEmail(emailText)
    : { signature: {}, sections: {}, thread: [], metadata: {} };

  const bidInfo = {
    project: parsed.sections.project || SE.extractProjectName(subject, emailText),
    gc: parsed.signature.company || SE.extractGCName(senderName, emailText),
    bidDate: SE.extractBidDate(emailText),
    location: parsed.sections.location || SE.extractLocation(emailText),
    scope: parsed.sections.scope || SE.extractScope(emailText),
    contact: senderName,
    email: senderEmail,
    phone: parsed.signature.phone || SE.extractPhone(emailText),

    projectManager: parsed.metadata.projectManager || parsed.signature.name || '',
    gcCompany: parsed.signature.company || SE.extractGCName(senderName, emailText),
    gcEmail: parsed.signature.email || senderEmail,
    gcPhone: parsed.signature.phone || SE.extractPhone(emailText),
    bidTime: parsed.metadata.bidTime || '',
    submissionInstructions: parsed.sections.submissionInstructions || '',
    preBidMeeting: parsed.metadata.preBidMeeting || { date: '', location: '', mandatory: false },
    addenda: parsed.metadata.addenda || [],
    bondRequirements: parsed.sections.bondRequirements || parsed.metadata.bondRequirements || '',
    generalNotes: parsed.sections.generalNotes || emailText,
    threadMessages: parsed.thread.length > 1
      ? parsed.thread
      : (threadTexts.length > 1
        ? threadTexts.map(t => ({ sender: '', date: '', body: t }))
        : []),

    attachments: await extractAttachments(),
    downloadLinks: SE.extractDownloadLinks(emailBody, PLATFORMS),
    notes: '',
    rawSubject: subject,
    rawText: emailText,
  };

  return bidInfo;
}

// Extract attachments
async function extractAttachments() {
  const attachments = [];
  const attachmentEls = document.querySelectorAll('.aQH, .aZo, [download_url]');

  attachmentEls.forEach(el => {
    const downloadUrl = el.getAttribute('download_url');
    const nameEl = el.querySelector('.aV3, .aQA') || el;
    const name = nameEl.innerText?.trim() || 'attachment';

    const relevantExtensions = ['.pdf', '.dwg', '.dxf', '.xlsx', '.xls', '.doc', '.docx', '.zip'];
    const isRelevant = relevantExtensions.some(ext => name.toLowerCase().includes(ext));

    if (downloadUrl || isRelevant) {
      attachments.push({
